class Vocab:
    def fit(self, xs):
        self.v={x:i for i,x in enumerate(sorted(set(xs)))}; return self
    def transform(self, xs):
        return [self.v.get(x, -1) for x in xs]
tf=Vocab().fit(["app","web","app"])
print("vocab", tf.v)
print("out", tf.transform(["web","branch"]))
